import sailpoint.object.Argument;
import sailpoint.object.Signature;
import sailpoint.object.TaskDefinition;

//Modify TaskDefinition of TaskResult, and clear its Returns

TaskDefinition taskDef = context.getObjectByName(TaskDefinition.class, "Ascension-TaskDefinition-ReconcileDuoADGroups");

wfcontext.getTaskResult().setDefinition(taskDef);

Argument arg1 = new Argument();
arg1.setName("Placeholder");
arg1.setType("int");
arg1.setPrompt("Placeholder");

List returnsList = new ArrayList();
returnsList.add(arg1);
  
Signature sig = wfcontext.getTaskResult().getDefinition().getSignature();
sig.setReturns(returnsList);
